import numpy as np
import matplotlib.pyplot as plt


def compute_system(params):
    lam = params["wavelength_um"]
    f_o = params["f_o_mm"]
    f_t = params["f_t_mm"] #focal length of the lens that converts separation into angle.
    NA = params["NA"]
    p = params["pixel_um"]
    nx = params["nx"]
    ny = params["ny"]
    s = params["separation_mm"] #beam separation at the imaging lens

    M = f_t / f_o # magnification
    pixel_scale = p / M  # object-space pixel size
    FOV_x_um = nx * pixel_scale 
    FOV_y_um = ny * pixel_scale

    resolution = lam / (2*NA)
    theta = s / f_t # small-angle approx, full angle between two beams.

    fringe_period = lam / np.sin(theta)
    fringe_spacing = fringe_period / p                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              

    return {
        "M": M,
        "pixel_scale": pixel_scale,
        "FOV_x_um": FOV_x_um,
        "FOV_y_um": FOV_y_um,
        "resolution_um": resolution,
        "theta_rad": theta,
        "fringe_spacing_pixels": fringe_spacing,
    }

def sweep(param_name, values, base):
    results = []

    for v in values:
        p = base.copy()
        p[param_name] = v
        results.append(compute_system(p))
    return results

def get(results, key):
    return np.array([r[key] for r in results])

if __name__ == "__main__":
    params = {
        "wavelength_um": 0.55,   
        "f_o_mm": 8.9,
        "f_t_mm": 148,
        "NA": 0.183,
        "pixel_um": 5,
        "nx": 320,
        "ny": 256,
        "separation_mm": 7,
    }

    results = compute_system(params)

    for key, value in results.items():
        print(f"{key:<22} = {value:.4f}")
